import React, { useState } from "react";

const API_BASE = "http://localhost:8080";

function Login({ onLogin, onSwitchToSignup }) {
  const [form, setForm] = useState({
    email: "",
    password: ""
  });
  const [message, setMessage] = useState("");

  function handleChange(e) {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  }

  async function handleLogin(e) {
    e.preventDefault();
    setMessage("");

    try {
      const response = await fetch(`${API_BASE}/auth/login`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(form)
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Login failed");
      }

      localStorage.setItem("canteenUser", JSON.stringify(data));
      onLogin(data);
    } catch (error) {
      setMessage(error.message || "Login failed");
    }
  }

  return (
    <div className="auth-page">
      <div className="auth-card">
        <h2>Login</h2>
        <p>Login to continue to the canteen system.</p>

        {message && <div className="message-banner">{message}</div>}

        <form onSubmit={handleLogin} className="auth-form">
          <input
            type="email"
            name="email"
            placeholder="Email"
            value={form.email}
            onChange={handleChange}
            required
          />

          <input
            type="password"
            name="password"
            placeholder="Password"
            value={form.password}
            onChange={handleChange}
            required
          />

          <button className="primary-btn full-width-btn" type="submit">
            Login
          </button>
        </form>

        <p className="auth-switch-text">
          Don&apos;t have an account?{" "}
          <button className="text-btn" onClick={onSwitchToSignup}>
            Signup
          </button>
        </p>
      </div>
    </div>
  );
}

export default Login;
